#include <iostream>
#include <string>
#include <sstream>
#include <vector>
#include <algorithm>

// This function represents the user's submitted main function, renamed for testing.
// It will be linked or included by the testing framework.
extern int user_main(); 

// Helper to normalize whitespace and remove trailing newlines for comparison
std::string normalize_output(const std::string& s) {
    std::string temp = s;
    // Remove trailing whitespace
    while (!temp.empty() && (temp.back() == '\n' || temp.back() == '\r' || temp.back() == ' ')) {
        temp.pop_back();
    }
    // Optional: Replace multiple newlines with single, trim leading/trailing space on lines
    std::string normalized_s;
    std::istringstream iss(temp);
    std::string line;
    while (std::getline(iss, line)) {
        // Trim whitespace from beginning and end of line
        size_t first = line.find_first_not_of(" \t\r\n");
        if (std::string::npos == first) {
            line.clear();
        } else {
            size_t last = line.find_last_not_of(" \t\r\n");
            line = line.substr(first, (last - first + 1));
        }
        if (!line.empty() || !normalized_s.empty()) { // Keep empty lines if not first
             if (!normalized_s.empty()) normalized_s += '\n';
             normalized_s += line;
        }
    }
    return normalized_s;
}

struct TestCase {
    std::string input;
    std::string expected_output;
};

int main() {
    std::vector<TestCase> test_cases = {
        {"1\n0", "Temp Conv\n1 C to F\n2 F to C\nOpt: C: 0.00C is 32.00F\n"},
        {"2\n212", "Temp Conv\n1 C to F\n2 F to C\nOpt: F: 212.00F is 100.00C\n"},
        {"1\n-10.5", "Temp Conv\n1 C to F\n2 F to C\nOpt: C: -10.50C is 13.10F\n"},
        {"2\n14", "Temp Conv\n1 C to F\n2 F to C\nOpt: F: 14.00F is -10.00C\n"},
        {"5\n10", "Temp Conv\n1 C to F\n2 F to C\nOpt: Bad opt.\n"}
    };

    int passed_tests = 0;
    for (size_t i = 0; i < test_cases.size(); ++i) {
        std::istringstream iss(test_cases[i].input);
        std::ostringstream oss;

        // Redirect std::cin and std::cout
        std::streambuf* old_cin = std::cin.rdbuf(iss.rdbuf());
        std::streambuf* old_cout = std::cout.rdbuf(oss.rdbuf());

        // Call the user's main function
        user_main();

        // Restore std::cin and std::cout
        std::cin.rdbuf(old_cin);
        std::cout.rdbuf(old_cout);

        std::string actual_output = normalize_output(oss.str());
        std::string expected_output = normalize_output(test_cases[i].expected_output);

        if (actual_output == expected_output) {
            std::cout << "Test Case " << i + 1 << " Passed.\n";
            passed_tests++;
        } else {
            std::cout << "Test Case " << i + 1 << " Failed.\n";
            std::cout << "Input:\n---\n" << test_cases[i].input << "\n---\n";
            std::cout << "Expected:\n---\n" << expected_output << "\n---\n";
            std::cout << "Actual:\n---\n" << actual_output << "\n---\n";
        }
    }

    std::cout << "\n" << passed_tests << "/" << test_cases.size() << " tests passed.\n";

    return 0;
}
